bool Assets::InitializePartition()
{
    partition_ = esp_partition_find_first(ESP_PARTITION_TYPE_DATA, ESP_PARTITION_SUBTYPE_DATA_SPIFFS, "assets");
    if (partition_ == nullptr) {
        ESP_LOGE(TAG, "Assets partition not found");
        partition_valid_ = false;
        return false;
    }

    if (partition_->size == 0) {
        ESP_LOGE(TAG, "Assets partition size is zero");
        partition_valid_ = false;
        return false;
    }

    esp_err_t err = esp_partition_mmap(partition_, 0, partition_->size, SPI_FLASH_MMAP_DATA, (const void**)&mmap_root_, &mmap_handle_);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to map assets partition: %s", esp_err_to_name(err));
        partition_valid_ = false;
        return false;
    }

    // Optional: Validate checksum
    uint32_t calculated_checksum = CalculateChecksum(mmap_root_, partition_->size);
    if (calculated_checksum != EXPECTED_CHECKSUM) {
        ESP_LOGE(TAG, "Assets checksum mismatch");
        checksum_valid_ = false;
        esp_partition_munmap(mmap_handle_);
        mmap_handle_ = 0;
        return false;
    }

    partition_valid_ = true;
    checksum_valid_ = true;

    // Load asset table or metadata here if applicable
    // Example: parseAssetsTable();

    return true;
}
```

#### 2. Memory Mapping Cleanup in Destructor
Used to safely unmap previously mapped partitions:
