Retrieves asset data based on internal lookup tables after initialization:
```cpp
bool Assets::GetAssetData(const std::string &name, void *&ptr, size_t &size)
{
    auto asset = assets_.find(name);
    if (asset == assets_.end()) {
        return false;
    }

    const char* data = mmap_root_ + asset->second.offset;

    // Check magic header if necessary
    if (data[0] != 'Z' || data[1] != 'Z') {
        ESP_LOGE(TAG, "Invalid asset magic number for %s", name.c_str());
        return false;
    }

    ptr = (void*)(data + 2); // Skip header
    size = asset->second.size;
    return true;
}
```

