esp_err_t Assets::Apply()
{
    // Step 1: Unmap previous mapping if exists
    if (mmap_handle_ != 0)
    {
        esp_partition_munmap(mmap_handle_);
        mmap_handle_ = 0;
        mmap_root_ = nullptr;
    }

    // Reset validation flags and clear assets
    partition_valid_ = false;
    checksum_valid_ = false;
    assets_.clear();

    // Step 2: Remap the partition into memory
    esp_err_t err = esp_partition_mmap(partition_, 0, partition_->size, ESP_PARTITION_MMAP_DATA, (const void **)&mmap_root_, &mmap_handle_);
    if (err != ESP_OK)
    {
        ESP_LOGE(TAG, "Failed to map partition: %s", esp_err_to_name(err));
        return err;
    }

    // Step 3: Validate Magic Number
    const char* magic = (const char*)mmap_root_;
    if (magic[0] != 'Z' || magic[1] != 'Z')
    {
        ESP_LOGE(TAG, "Invalid magic number detected: %02x%02x", magic[0], magic[1]);
        esp_partition_munmap(mmap_handle_);
        mmap_handle_ = 0;
        mmap_root_ = nullptr;
        return ESP_FAIL;
    }

    // Step 4: Extract metadata
    uint32_t stored_files = *(uint32_t*)(mmap_root_ + 0);
    uint32_t stored_checksum = *(uint32_t*)(mmap_root_ + 4);
    uint32_t data_length = *(uint32_t*)(mmap_root_ + 8);

    // Optional: sanity check on length
    if (data_length > partition_->size - 12)
    {
        ESP_LOGE(TAG, "Data length exceeds partition size");
        esp_partition_munmap(mmap_handle_);
        mmap_handle_ = 0;
        mmap_root_ = nullptr;
        return ESP_ERR_INVALID_SIZE;
    }

    // Step 5: Compute and compare checksum
    auto calc_start = esp_timer_get_time();
    uint32_t computed_checksum = CalculateChecksum((const char*)mmap_root_ + 12, data_length);
    auto calc_end = esp_timer_get_time();

    ESP_LOGD(TAG, "Checksum computed in %lld us", (calc_end - calc_start));

    if (computed_checksum != stored_checksum)
    {
        ESP_LOGE(TAG, "Checksum mismatch: expected %u, got %u", stored_checksum, computed_checksum);
        esp_partition_munmap(mmap_handle_);
        mmap_handle_ = 0;
        mmap_root_ = nullptr;
        return ESP_ERR_INVALID_CRC;
    }

    // Mark checksum as valid
    checksum_valid_ = true;

    // Step 6: Rebuild assets table
    for (uint32_t i = 0; i < stored_files; i++)
    {
        auto item = (const mmap_assets_table*)(mmap_root_ + 12 + i * sizeof(mmap_assets_table));
        auto asset = Asset{
            .size = static_cast<size_t>(item->asset_size),
            .offset = static_cast<size_t>(12 + sizeof(mmap_assets_table) * stored_files + item->asset_offset)
        };
        assets_[item->asset_name] = asset;
    }

    // Mark partition as valid
    partition_valid_ = true;

    ESP_LOGI(TAG, "Asset applied successfully.");
    return ESP_OK;
}

