#include <functional>
#include <string>
#include <memory>
#include "esp_log.h"
#include "esp_timer.h"
#include "http.h"

static const char* TAG = "AssetManager";

void Download(std::string url, std::function<void(int progress, size_t speed)> progress_callback) {
    ESP_LOGI(TAG, "Starting download from URL: %s", url.c_str());

    // Initialize HTTP client
    auto http = std::make_unique<Http>();
    if (!http) {
        ESP_LOGE(TAG, "Failed to create HTTP client");
        if (progress_callback) {
            try {
                progress_callback(-1, 0); // Indicate error with negative progress
            } catch (...) {
                ESP_LOGW(TAG, "Progress callback threw an exception");
            }
        }
        return;
    }

    // Configure request (example assumes GET)
    http->setUrl(url);
    http->setMethod(HTTP_METHOD_GET);

    // Open connection
    if (!http->open()) {
        ESP_LOGE(TAG, "Failed to open HTTP connection to URL: %s", url.c_str());
        if (progress_callback) {
            try {
                progress_callback(-1, 0); // Indicate error
            } catch (...) {
                ESP_LOGW(TAG, "Progress callback threw an exception");
            }
        }
        return;
    }

    constexpr size_t kBufferSize = 4096;
    uint8_t buffer[kBufferSize];
    size_t total_bytes = 0;
    int last_reported_progress = -1;
    uint32_t last_progress_time = 0;

    auto start_time = esp_timer_get_time();

    // Get content length for progress calculation
    size_t content_length = http->getContentLength();

    while (true) {
        ssize_t bytes_read = http->read(buffer, sizeof(buffer));
        if (bytes_read < 0) {
            ESP_LOGE(TAG, "Error reading data from URL: %s", url.c_str());
            http->close();
            if (progress_callback) {
                try {
                    progress_callback(-1, 0); // Indicate error
                } catch (...) {
                    ESP_LOGW(TAG, "Progress callback threw an exception");
                }
            }
            return;
        }

        if (bytes_read == 0) {
            // End of stream
            break;
        }

        total_bytes += bytes_read;

        // Calculate progress if Content-Length is known
        int progress_percent = (content_length > 0) ? (total_bytes * 100 / content_length) : 0;

        // Get current time for throttling progress updates
        auto now = esp_timer_get_time();
        uint64_t elapsed_us = now - start_time;
        uint64_t elapsed_ms = elapsed_us / 1000;

        // Report progress either when percentage changes or every 500ms to ensure smooth updates
        uint32_t current_time_ms = elapsed_ms;
        bool should_report = (progress_percent != last_reported_progress) || 
                            (current_time_ms - last_progress_time > 500) ||
                            (content_length > 0 && progress_percent == 100);

        if (should_report && progress_callback) {
            size_t speed_bps = (elapsed_ms > 0) ? (total_bytes * 1000ULL) / elapsed_ms : 0;
            try {
                progress_callback(progress_percent, speed_bps);
            } catch (...) {
                ESP_LOGW(TAG, "Progress callback threw an exception");
            }

            last_reported_progress = progress_percent;
            last_progress_time = current_time_ms;
        }

        // TODO: Write data to destination (file, flash, etc.)
        // This would typically involve writing the buffer content somewhere
        // For example: fwrite(buffer, 1, bytes_read, output_file);
        // In the context of this asset system, you might want to:
        // 1. Write to a temporary file
        // 2. Process and store in the assets partition
        // 3. Or handle according to your specific asset management strategy
    }

    http->close();

    // Final progress update at 100%
    if (progress_callback && last_reported_progress != 100) {
        auto end_time = esp_timer_get_time();
        uint64_t total_elapsed_ms = (end_time - start_time) / 1000;
        size_t final_speed = (total_elapsed_ms > 0) ? (total_bytes * 1000ULL) / total_elapsed_ms : 0;
        try {
            progress_callback(100, final_speed);
        } catch (...) {
            ESP_LOGW(TAG, "Final progress callback threw an exception");
        }
    }

    ESP_LOGI(TAG, "Download completed. Total bytes received: %d", total_bytes);
