    config.transport_type = HTTP_TRANSPORT_UNKNOWN;
    config.timeout_ms = 10000;

    esp_http_client_handle_t client = esp_http_client_init(&config);
    if (!client) {
        ESP_LOGE(TAG, "Failed to initialize HTTP client");
        return false;
    }

    esp_err_t err = esp_http_client_open(client, 0);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to open HTTP connection: %s", esp_err_to_name(err));
        esp_http_client_cleanup(client);
        return false;
    }

    int content_length = esp_http_client_fetch_headers(client);
    if (content_length <= 0) {
        ESP_LOGW(TAG, "Invalid content length");
        esp_http_client_close(client);
        esp_http_client_cleanup(client);
        return false;
    }

    // Initialize OTA upgrade
    esp_ota_handle_t update_handle = 0;
    const esp_partition_t *update_partition = esp_ota_get_next_update_partition(NULL);
    if (update_partition == NULL) {
        ESP_LOGE(TAG, "Failed to get next update partition");
        esp_http_client_close(client);
        esp_http_client_cleanup(client);
        return false;
    }

    ESP_LOGI(TAG, "Writing to partition subtype %d at offset 0x%x",
             update_partition->subtype, update_partition->address);

    err = esp_ota_begin(update_partition, OTA_SIZE_UNKNOWN, &update_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_begin failed (%s)", esp_err_to_name(err));
        esp_http_client_close(client);
        esp_http_client_cleanup(client);
        return false;
    }

    const size_t BUFFER_SIZE = 1024;
    std::vector<uint8_t> buffer(BUFFER_SIZE);
    size_t total_read = 0;
    auto start_time = std::chrono::steady_clock::now();

    while (total_read < content_length) {
        int read_len = esp_http_client_read(client, reinterpret_cast<char*>(buffer.data()), BUFFER_SIZE);
        if (read_len < 0) {
            ESP_LOGE(TAG, "Error occurred while reading HTTP stream");
            esp_ota_abort(update_handle);
            esp_http_client_close(client);
            esp_http_client_cleanup(client);
            return false;
        }

        if (read_len == 0) {
            // End of stream
            break;
        }

        // Write to flash
        err = esp_ota_write(update_handle, buffer.data(), read_len);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "esp_ota_write failed (%s)", esp_err_to_name(err));
            esp_ota_abort(update_handle);
            esp_http_client_close(client);
            esp_http_client_cleanup(client);
            return false;
        }

        total_read += read_len;

        // Calculate progress
        int progress = static_cast<int>((static_cast<float>(total_read) / content_length) * 100);

        // Speed estimation
        auto now = std::chrono::steady_clock::now();
        auto duration = std::chrono::duration_cast<std::chrono::milliseconds>(now - start_time).count();
        size_t speed = 0;
        if (duration > 0) {
            speed = (total_read * 1000) / duration; // Bytes/sec
        }

        // Notify progress
        if (callback) {
            callback(progress, speed);
        }
    }

    esp_http_client_close(client);
    esp_http_client_cleanup(client);

    // Finish OTA upgrade
    err = esp_ota_end(update_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_end failed (%s)!", esp_err_to_name(err));
        return false;
    }

    // Set boot partition
    err = esp_ota_set_boot_partition(update_partition);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "esp_ota_set_boot_partition failed (%s)!", esp_err_to_name(err));
        return false;
    }

    ESP_LOGI(TAG, "OTA Upgrade completed: %d bytes read.", total_read);
    ESP_LOGI(TAG, "Prepare to restart system!");

    // Restart system to boot from new firmware
    esp_restart();

    return true;
}

