void Es8388AudioCodec::EnableInput(bool enable) {
    std::lock_guard<std::mutex> lock(data_if_mutex_);

    // Early return if no change needed
    if (enable == input_enabled_) {
        return;
    }

    if (enable) {
        // Configure and open input device
        esp_codec_dev_sample_info_t fs = {
            .bits_per_sample = 16,
            .channel = (uint8_t)input_channels_,
            .channel_mask = ESP_CODEC_DEV_MAKE_CHANNEL_MASK(input_channels_ == 1 ? 0 : 1),
            .sample_rate = (uint32_t)input_sample_rate_,
            .mclk_multiple = I2S_MCLK_MULTIPLE_256,
        };

        if (input_dev_ != nullptr) {
            esp_err_t ret = esp_codec_dev_open(input_dev_, &fs);
            if (ret != ESP_OK) {
                ESP_LOGE(TAG, "Failed to open input device: %s", esp_err_to_name(ret));
                return;
            }
        }

        // Configure ES8388 ADC and input path
        // ADC Power Control - power up ADC, VMID=50K
        uint8_t reg_val = 0xC0;
        if (ctrl_if_ && ctrl_if_->write_reg) {
            ctrl_if_->write_reg(ctrl_if_, 0x00, 1, &reg_val, 1);
        }

        // ADC Control 1 - ADC format setting
        reg_val = 0x00; // Normal mode, LRP=0, LRSWAP=0, MS=0, SIN=0
        if (ctrl_if_ && ctrl_if_->write_reg) {
            ctrl_if_->write_reg(ctrl_if_, 0x01, 1, &reg_val, 1);
        }

        // ADC Control 2 - ADC MCLK/LRCK ratio
        reg_val = 0xF0; // Default setting
        if (ctrl_if_ && ctrl_if_->write_reg) {
            ctrl_if_->write_reg(ctrl_if_, 0x02, 1, &reg_val, 1);
        }

        // ADC Data Control - ADC left/right data swap
        reg_val = 0x00; // Normal operation
        if (ctrl_if_ && ctrl_if_->write_reg) {
            ctrl_if_->write_reg(ctrl_if_, 0x03, 1, &reg_val, 1);
        }

        // Select Analog Input - LIN2/RIN2 as input
        reg_val = 0x50; // LINSEL=01, RINSEL=01 (LIN2/RIN2 selected)
        if (ctrl_if_ && ctrl_if_->write_reg) {
            ctrl_if_->write_reg(ctrl_if_, 0x04, 1, &reg_val, 1);
        }

        // ADC Control 9 - MIC Amplifier Gain Setting
        reg_val = 0x00; // MIC amplified gain setting
        if (ctrl_if_ && ctrl_if_->write_reg) {
            ctrl_if_->write_reg(ctrl_if_, 0x08, 1, &reg_val, 1);
        }

        // ADC Volume Control - Set ADC volume (0x09 for left, 0x0A for right)
        uint8_t adc_vol = 0x20; // Medium volume setting
        if (ctrl_if_ && ctrl_if_->write_reg) {
            ctrl_if_->write_reg(ctrl_if_, 0x09, 1, &adc_vol, 1);
            ctrl_if_->write_reg(ctrl_if_, 0x0A, 1, &adc_vol, 1);
        }

        // Turn on peripheral amplifier if applicable
        if (pa_pin_ != GPIO_NUM_NC) {
            gpio_set_level(pa_pin_, 1);
        }
    } else {
        // Mute ADC inputs
        uint8_t mute_val = 0x00;
        if (ctrl_if_ && ctrl_if_->write_reg) {
            ctrl_if_->write_reg(ctrl_if_, 0x09, 1, &mute_val, 1);
            ctrl_if_->write_reg(ctrl_if_, 0x0A, 1, &mute_val, 1);
        }

        // Power down ADC
        uint8_t reg_val = 0x00;
        if (ctrl_if_ && ctrl_if_->write_reg) {
            ctrl_if_->write_reg(ctrl_if_, 0x00, 1, &reg_val, 1);
        }

        // Close input device when disabling
        if (input_dev_ != nullptr) {
            esp_codec_dev_close(input_dev_);
        }

        // Turn off peripheral amplifier if applicable
        if (pa_pin_ != GPIO_NUM_NC) {
            gpio_set_level(pa_pin_, 0);
        }
    }

    // Sync with base class state
    AudioCodec::EnableInput(enable);
}

