void AfeWakeWord::AudioDetectionTask(void *arg)
{
    if (arg == nullptr)
    {
        ESP_LOGE(TAG, "Invalid argument passed to AudioDetectionTask");
        vTaskDelete(nullptr);
        return;
    }

    auto *self = static_cast<AfeWakeWord *>(arg);

    auto fetch_size = self->afe_iface_->get_fetch_chunksize(self->afe_data_);
    auto feed_size = self->afe_iface_->get_feed_chunksize(self->afe_data_);
    ESP_LOGI(TAG, "Audio detection task started, feed size: %d fetch size: %d", 
             feed_size, fetch_size);

    while (true)
    {
        // Wait until detection is enabled via event group
        EventBits_t bits = xEventGroupWaitBits(
            self->event_group_,
            DETECTION_RUNNING_EVENT,
            pdFALSE, // Do not clear bit on exit
            pdTRUE,  // Wait for all bits
            portMAX_DELAY);

        if (!(bits & DETECTION_RUNNING_EVENT))
        {
            continue; // Shouldn't happen due to portMAX_DELAY but added for safety
