void AFEWakeWord::EncodeWakeWordData()
{
    // Check if encoding task is already running
    if (wake_word_encode_task_ != nullptr) {
        ESP_LOGW(TAG, "Wake word encoding task is already running");
        return;
    }

    const size_t stack_size = 4096 * 7;

    // Allocate stack memory if not already allocated
    if (wake_word_encode_task_stack_ == nullptr) {
        wake_word_encode_task_stack_ = (StackType_t*)heap_caps_malloc(stack_size, MALLOC_CAP_SPIRAM);
        if (wake_word_encode_task_stack_ == nullptr) {
            ESP_LOGE(TAG, "Failed to allocate stack memory for wake word encoding task");
            return;
        }
    }

    // Allocate task buffer if not already allocated
    if (wake_word_encode_task_buffer_ == nullptr) {
        wake_word_encode_task_buffer_ = (StaticTask_t*)heap_caps_malloc(sizeof(StaticTask_t), MALLOC_CAP_INTERNAL);
        if (wake_word_encode_task_buffer_ == nullptr) {
            ESP_LOGE(TAG, "Failed to allocate task buffer for wake word encoding task");
            return;
        }
    }

    // Create the static task
    wake_word_encode_task_ = xTaskCreateStatic(
        [](void* arg) {
            auto this_ = (AFEWakeWord*)arg;

            // Create Opus encoder
            auto encoder = std::make_unique<OpusEncoderWrapper>(16000, 1, OPUS_FRAME_DURATION_MS);
            encoder->SetComplexity(0); // Optimize for speed

            // Process PCM data continuously until task is terminated
            while (true) {
                // Lock mutex to access PCM queue
                std::unique_lock<std::mutex> lock(this_->wake_word_mutex_);

                // Wait for PCM data to be available
                this_->wake_word_cv_.wait(lock, [this_]() {
                    return !this_->wake_word_pcm_.empty() || this_->wake_word_encode_task_ == nullptr;
                });

                // Check if task should terminate
                if (this_->wake_word_encode_task_ == nullptr) {
                    break;
                }

                // Get PCM data from front of queue
                if (!this_->wake_word_pcm_.empty()) {
                    auto pcm = std::move(this_->wake_word_pcm_.front());
                    this_->wake_word_pcm_.pop_front();
                    lock.unlock(); // Unlock early to avoid blocking during encoding

                    // Encode the PCM data
                    encoder->Encode(std::move(pcm), [this_](std::vector<uint8_t>&& opus) {
                        std::lock_guard<std::mutex> lock(this_->wake_word_mutex_);
                        this_->wake_word_opus_.emplace_back(std::move(opus));
                        this_->wake_word_opus_cv_.notify_all();
                    });
                }
            }

            // Clean up resources
            std::lock_guard<std::mutex> lock(this_->wake_word_mutex_);
            this_->wake_word_encode_task_ = nullptr;

            vTaskDelete(NULL);
        }, 
        "WakeWordEncode", 
        stack_size, 
        this, 
        configMAX_PRIORITIES - 1,
        wake_word_encode_task_stack_, 
        wake_word_encode_task_buffer_
    );

    if (wake_word_encode_task_ == nullptr) {
        ESP_LOGE(TAG, "Failed to create wake word encoding task");
    }
}

