void CustomWakeWord::ParseWakenetModelConfig()
{
    // Example assumed input: a JSON config string stored in member variable json_config_
    const char* json_content = json_config_.c_str();
    cJSON *json = cJSON_Parse(json_content);
    if (json == nullptr)
    {
        ESP_LOGE(TAG, "Failed to parse JSON config");
        return;
    }

    // Parse threshold
    cJSON *threshold = cJSON_GetObjectItemCaseSensitive(json, "threshold");
    if (cJSON_IsNumber(threshold))
    {
        threshold_ = threshold->valuedouble;
        ESP_LOGI(TAG, "Parsed threshold: %.2f", threshold_->valuedouble);
    }

    // Parse duration
    cJSON *duration = cJSON_GetObjectItemCaseSensitive(json, "duration");
    if (cJSON_IsNumber(duration))
    {
        duration_ = duration->valueint;
        ESP_LOGI(TAG, "Parsed duration: %d", duration_);
    }
    else
    {
        duration_ = 5000; // Default duration
    }

    // Parse language
    cJSON *language = cJSON_GetObjectItemCaseSensitive(json, "language");
    if (cJSON_IsString(language) && language->valuestring != nullptr)
    {
        language_ = std::string(language->valuestring);
        ESP_LOGI(TAG, "Parsed language: %s", language_.c_str());
    }

    // Select wakeword model name based on language
    wn_name_ = esp_srmodel_filter(models_, ESP_WN_PREFIX, language_.c_str());
    if (wn_name_ == nullptr)
    {
        ESP_LOGW(TAG, "Language-specific wakeword model not found, trying default.");
        wn_name_ = esp_srmodel_filter(models_, ESP_WN_PREFIX, NULL);
    }

    if (wn_name_)
    {
        wakenet_ = esp_wn_handle_from_name(wn_name_);
        ESP_LOGI(TAG, "Loaded wakeword model: %s", wn_name_);
    }
    else
    {
        ESP_LOGE(TAG, "No valid wakeword model could be loaded!");
        cJSON_Delete(json);
        return;
    }

    // Select multinet model name based on language
    mn_name_ = esp_srmodel_filter(models_, ESP_MN_PREFIX, language_.c_str());
    if (mn_name_ == nullptr)
    {
        ESP_LOGW(TAG, "Language-specific multinet model not found, trying default.");
        mn_name_ = esp_srmodel_filter(models_, ESP_MN_PREFIX, NULL);
    }

    if (mn_name_)
    {
        multinet_ = esp_mn_handle_from_name(mn_name_);
        multinet_model_data_ = multinet_->create(mn_name_, duration_); // Use parsed duration
        multinet_->set_det_threshold(multinet_model_data_, threshold_);
        ESP_LOGI(TAG, "Loaded multinet model: %s", mn_name_);
    }
    else
    {
        ESP_LOGE(TAG, "No valid multinet model could be loaded!");
        cJSON_Delete(json);
        return;
    }

    // Clear previous commands
    esp_mn_commands_clear();

    // Parse commands array
    cJSON *commands = cJSON_GetObjectItemCaseSensitive(json, "commands");
    if (cJSON_IsArray(commands))
    {
        int cmd_id = 1;
        for (int i = 0; i < cJSON_GetArraySize(commands); i++)
        {
            cJSON *command_obj = cJSON_GetArrayItem(commands, i);
            if (!cJSON_IsObject(command_obj)) continue;

            cJSON *name_item = cJSON_GetObjectItemCaseSensitive(command_obj, "name");
            cJSON *text_item = cJSON_GetObjectItemCaseSensitive(command_obj, "text");
            cJSON *action_item = cJSON_GetObjectItemCaseSensitive(command_obj, "action");

            if (cJSON_IsString(name_item) && cJSON_IsString(text_item) && cJSON_IsString(action_item))
            {
                CommandEntry entry{
                    .command = std::string(name_item->valuestring),
                    .text = std::string(text_item->valuestring),
                    .action = std::string(action_item->valuestring)
                };
                commands_.push_back(entry);

                // Register command ID with internal system
                esp_mn_commands_add(cmd_id, entry.command.c_str());

                ESP_LOGI(TAG, "Registered command [%d]: Name=%s Text=%s Action=%s",
                         cmd_id,
                         entry.command.c_str(),
                         entry.text.c_str(),
                         entry.action.c_str());

                cmd_id++;
            }
        }

        // Finalize command list update
        esp_mn_commands_update();
    }

    // Cleanup
    cJSON_Delete(json);
}

