        return false;
    }

    // Ensure duration_ has a default value
    if (duration_ <= 0) {
        duration_ = 5000;
    }

    // Select multinet model based on language
    mn_name_ = esp_srmodel_filter(models_, ESP_MN_PREFIX, language_.c_str());
    if (mn_name_ == nullptr)
    {
        ESP_LOGW(TAG, "Language '%s' multinet model not found, falling back to default.", language_.c_str());
        mn_name_ = esp_srmodel_filter(models_, ESP_MN_PREFIX, NULL);
    }

    if (mn_name_ == nullptr)
    {
