        return false;
    }

    // Load multinet handle and create instance
    multinet_ = esp_mn_handle_from_name(mn_name_);
    if (!multinet_)
    {
        ESP_LOGE(TAG, "Failed to get multinet handle from name: %s", mn_name_);
        return false;
    }

    multinet_model_data_ = multinet_->create(mn_name_, duration_);
    if (!multinet_model_data_)
    {
        ESP_LOGE(TAG, "Failed to create multinet model data");
        return false;
    }

    // Configure detection threshold
    if (threshold_ > 0) {
        multinet_->set_det_threshold(multinet_model_data_, threshold_);
    }

    // Register custom commands
    esp_mn_commands_clear();
    for (size_t i = 0; i < commands_.size(); ++i)
    {
        esp_mn_commands_add(static_cast<int>(i + 1), commands_[i].command.c_str());
    }
    esp_mn_commands_update();

    // Optional debug print of active commands
    multinet_->print_active_speech_commands(multinet_model_data_);

    ESP_LOGI(TAG, "Multinet initialized successfully with model: %s", mn_name_);
