void CustomWakeWord::Feed(const std::vector<int16_t> &data)
{
    // Early exit if not running or no model loaded
    if (!running_ || multinet_model_data_ == nullptr || multinet_ == nullptr)
    {
        return;
    }

    // Validate codec is available
    if (codec_ == nullptr)
    {
        ESP_LOGE(TAG, "Audio codec not initialized");
        return;
    }

    std::vector<int16_t> mono_data;

    // Convert stereo to mono if needed
    if (codec_->input_channels() == 2)
    {
        if (data.size() % 2 != 0)
        {
            ESP_LOGW(TAG, "Stereo data size is odd, truncating last sample");
        }

        size_t mono_size = data.size() / 2;
        mono_data.resize(mono_size);

        for (size_t i = 0; i < mono_size; ++i)
        {
            mono_data[i] = data[i * 2]; // Take left channel
        }
    }
    else
    {
        mono_data = data;
    }

    // Store audio data for buffering (used for wake word capture/encoding)
    StoreWakeWordData(mono_data);

    // Run detection on mono data
    esp_mn_state_t mn_state = multinet_->detect(
        multinet_model_data_,
        const_cast<int16_t*>(mono_data.data())
    );

    // Process detection result
    switch (mn_state)
    {
        case ESP_MN_STATE_DETECTING:
            return;

        case ESP_MN_STATE_DETECTED:
        {
            esp_mn_results_t* mn_result = multinet_->get_results(multinet_model_data_);
            if (mn_result == nullptr)
            {
                ESP_LOGE(TAG, "Failed to get detection results");
                return;
            }

            for (int i = 0; i < mn_result->num && running_; i++)
            {
                ESP_LOGI(TAG, "Custom wake word detected: command_id=%d, string=%s, prob=%f",
                         mn_result->command_id[i], mn_result->string, mn_result->prob[i]);

                // Adjust index since command IDs start at 1
                int cmd_index = mn_result->command_id[i] - 1;

                if (cmd_index >= 0 && cmd_index < static_cast<int>(commands_.size()))
                {
                    auto& command = commands_[cmd_index];

                    if (command.action == "wake")
                    {
                        last_detected_wake_word_ = command.text;
                        running_ = false;

                        if (wake_word_detected_callback_)
                        {
                            wake_word_detected_callback_(last_detected_wake_word_);
                        }
                        break;
                    }
                }
                else
                {
                    ESP_LOGW(TAG, "Invalid command index: %d (commands size: %d)", 
                             cmd_index, static_cast<int>(commands_.size()));
                }
            }

            multinet_->clean(multinet_model_data_);
            break;
        }

        case ESP_MN_STATE_TIMEOUT:
            ESP_LOGD(TAG, "Command word detection timeout, cleaning state");
            multinet_->clean(multinet_model_data_);
            break;

        default:
            ESP_LOGD(TAG, "Unknown detection state: %d", mn_state);
            break;
    }
}

