        if (state_buffer_.size() < 2) return 0.0f;

        float s_minus_1 = state_buffer_[1];
        float s_minus_2 = state_buffer_[0];
        float real_part = cos_coefficient_ * s_minus_1 - s_minus_2;
        float imaginary_part = sin_coefficient_ * s_minus_1;

        return std::sqrt(real_part * real_part + imaginary_part * imaginary_part) /
               (static_cast<float>(window_size_) / 2.0f);
    }
};
```

#### 2. Audio Signal Processing Pipeline (`AudioSignalProcessor`)
Processes incoming audio samples and outputs probabilities indicating whether each segment corresponds to a Mark or Space tone.

```cpp
class AudioSignalProcessor
{
private:
    std::deque<float> input_buffer_;
    size_t input_buffer_size_;
    size_t output_sample_count_;
    size_t samples_per_bit_;
    std::unique_ptr<FrequencyDetector> mark_detector_;
    std::unique_ptr<FrequencyDetector> space_detector_;

public:
    AudioSignalProcessor(size_t sample_rate, size_t mark_frequency, size_t space_frequency,
                         size_t bit_rate, size_t window_size)
        : input_buffer_size_(window_size), output_sample_count_(0)
    {
        float normalized_mark_freq = static_cast<float>(mark_frequency) / static_cast<float>(sample_rate);
        float normalized_space_freq = static_cast<float>(space_frequency) / static_cast<float>(sample_rate);

        mark_detector_ = std::make_unique<FrequencyDetector>(normalized_mark_freq, window_size);
        space_detector_ = std::make_unique<FrequencyDetector>(normalized_space_freq, window_size);

        samples_per_bit_ = sample_rate / bit_rate;
    }

    std::vector<float> ProcessAudioSamples(const std::vector<float> &samples)
    {
        std::vector<float> probabilities;
        for (float sample : samples)
        {
            input_buffer_.push_back(sample);
            if (input_buffer_.size() > input_buffer_size_)
            {
                input_buffer_.pop_front();
            }

            mark_detector_->ProcessSample(sample);
            space_detector_->ProcessSample(sample);

            if (++output_sample_count_ >= samples_per_bit_)
            {
                float mark_amplitude = mark_detector_->GetAmplitude();
                float space_amplitude = space_detector_->GetAmplitude();

                float total_amplitude = mark_amplitude + space_amplitude;
                float probability = (total_amplitude > 0.0f) ? (mark_amplitude / total_amplitude) : 0.5f;

                probabilities.push_back(probability);
                output_sample_count_ = 0;
            }
        }
        return probabilities;
    }
};
```

#### 3. Bit Stream Decoding and State Machine Handling (`AudioDataBuffer`)
Manages decoding of binary data from probability streams, including synchronization markers and checksum validation.

```cpp
enum class DataReceptionState
{
    kInactive,
    kWaiting,
    kReceiving
};

class AudioDataBuffer
{
private:
    DataReceptionState current_state_;
    std::deque<uint8_t> identifier_buffer_;
    size_t identifier_buffer_size_;
    std::vector<uint8_t> bit_buffer_;
    size_t max_bit_buffer_size_;
    const std::vector<uint8_t> start_of_transmission_;
    const std::vector<uint8_t> end_of_transmission_;
    bool enable_checksum_validation_;

public:
    std::optional<std::string> decoded_text;

    bool ProcessProbabilityData(const std::vector<float> &probabilities, float threshold = 0.5f)
    {
        for (float probability : probabilities)
        {
            uint8_t bit = (probability > threshold) ? 1 : 0;

            if (identifier_buffer_.size() >= identifier_buffer_size_)
            {
                identifier_buffer_.pop_front();
            }
            identifier_buffer_.push_back(bit);

            switch (current_state_)
            {
            case DataReceptionState::kInactive:
                if (identifier_buffer_.size() >= start_of_transmission_.size())
                {
                    current_state_ = DataReceptionState::kWaiting;
                }
                break;

            case DataReceptionState::kWaiting:
                if (identifier_buffer_.size() >= start_of_transmission_.size())
                {
                    std::vector<uint8_t> snapshot(identifier_buffer_.begin(), identifier_buffer_.end());
                    if (snapshot == start_of_transmission_)
                    {
                        ClearBuffers();
                        current_state_ = DataReceptionState::kReceiving;
                    }
                }
                break;

            case DataReceptionState::kReceiving:
                bit_buffer_.push_back(bit);
                if (identifier_buffer_.size() >= end_of_transmission_.size())
                {
                    std::vector<uint8_t> snapshot(identifier_buffer_.begin(), identifier_buffer_.end());
                    if (snapshot == end_of_transmission_)
                    {
                        current_state_ = DataReceptionState::kInactive;

                        std::vector<uint8_t> bytes = ConvertBitsToBytes(bit_buffer_);
                        // Handle checksum and decode text...
                        std::string result(bytes.begin(), bytes.end());
                        decoded_text = result;
                        ClearBuffers();
                        return true;
                    }
                    else if (bit_buffer_.size() >= max_bit_buffer_size_)
                    {
                        ClearBuffers();
                        current_state_ = DataReceptionState::kInactive;
                    }
                }
                break;
            }
        }
        return false;
    }

private:
    void ClearBuffers()
    {
        identifier_buffer_.clear();
        bit_buffer_.clear();
    }

    std::vector<uint8_t> ConvertBitsToBytes(const std::vector<uint8_t> &bits) const
    {
        std::vector<uint8_t> bytes;
        size_t complete_bytes_count = bits.size() / 8;
        bytes.reserve(complete_bytes_count);

        for (size_t i = 0; i < complete_bytes_count; ++i)
        {
            uint8_t byte_value = 0;
            for (size_t j = 0; j < 8; ++j)
            {
                byte_value |= bits[i * 8 + j] << (7 - j);
            }
            bytes.push_back(byte_value);
        }
        return bytes;
    }
};
```

