std::string WifiBoard::GetDeviceStatusJson()
{
    auto& board = Board::GetInstance();
    auto root = cJSON_CreateObject();

    // System Info
    auto sys = cJSON_CreateObject();
    cJSON_AddStringToObject(sys, "board", board.GetBoardType().c_str());
    cJSON_AddStringToObject(sys, "version", SYSTEM_VERSION);
    cJSON_AddStringToObject(sys, "hostname", Settings::GetString(CONFIG_HOSTNAME).c_str());
    cJSON_AddItemToObject(root, "system", sys);

    // Provisioning Methods
    auto provisioning = cJSON_CreateArray();
#ifdef CONFIG_USE_HOTSPOT_WIFI_PROVISIONING
    cJSON_AddItemToArray(provisioning, cJSON_CreateString("hotspot"));
#endif
