    cJSON_AddItemToArray(provisioning, cJSON_CreateString("blufi"));
#endif
#ifdef CONFIG_USE_ACOUSTIC_WIFI_PROVISIONING
    cJSON_AddItemToArray(provisioning, cJSON_CreateString("acoustic"));
#endif
    cJSON_AddItemToObject(root, "provisioning", provisioning);

    // Screen Information
    auto screen = cJSON_CreateObject();
    if (auto display = board.GetDisplay(); display && display->height() > 64) {
        cJSON_AddBoolToObject(screen, "available", true);
        cJSON_AddNumberToObject(screen, "width", display->width());
        cJSON_AddNumberToObject(screen, "height", display->height());
        if (auto theme = display->GetTheme()) {
            cJSON_AddStringToObject(screen, "theme", theme->name().c_str());
        }
    } else {
        cJSON_AddBoolToObject(screen, "available", false);
    }
    cJSON_AddItemToObject(root, "screen", screen);

    // Battery Status
    int level = 0;
    bool charging = false, discharging = false;
    if (board.GetBatteryLevel(level, charging, discharging)) {
        auto battery = cJSON_CreateObject();
        cJSON_AddNumberToObject(battery, "level", level);
        cJSON_AddBoolToObject(battery, "charging", charging);
        cJSON_AddBoolToObject(battery, "discharging", discharging);
        cJSON_AddItemToObject(root, "battery", battery);
    }

    // Network Status
    auto& wifi = WifiManager::GetInstance();
    auto network = cJSON_CreateObject();
    cJSON_AddStringToObject(network, "type", "wifi");
    cJSON_AddStringToObject(network, "ssid", wifi.GetSsid().c_str());
    int rssi = wifi.GetRssi();
    const char* signal = rssi >= -60 ? "strong" : (rssi >= -70 ? "medium" : "weak");
    cJSON_AddStringToObject(network, "signal", signal);
    cJSON_AddItemToObject(root, "network", network);

    // Chip Temperature
    float temp = 0.0f;
    if (board.GetTemperature(temp)) {
        auto chip = cJSON_CreateObject();
        cJSON_AddNumberToObject(chip, "temperature", temp);
        cJSON_AddItemToObject(root, "chip", chip);
    }

    char* str = cJSON_PrintUnformatted(root);
    std::string result(str);
    cJSON_free(str);
    cJSON_Delete(root);
    return result;
}
```

