bool WebsocketProtocol::Start()
{
    // Step 1: Load configuration from NVS
    Settings settings("websocket", false);
    std::string url = settings.GetString("url");
    std::string token = settings.GetString("token");
    int version = settings.GetInt("version", 1); // Default to version 1 if not set
    if (version != 0) {
        version_ = version;
    }

    if (url.empty())
    {
        ESP_LOGE(TAG, "WebSocket URL not configured.");
        SetError(Lang::Strings::INVALID_CONFIGURATION);
        return false;
    }

    // Step 2: Create and configure WebSocket
    auto network = Board::GetInstance().GetNetwork();
    websocket_ = network->CreateWebSocket(1);

    if (!token.empty())
    {
        if (token.find(" ") == std::string::npos)
        {
            token = "Bearer " + token;
        }
        websocket_->SetHeader("Authorization", token.c_str());
    }

    websocket_->SetHeader("Protocol-Version", std::to_string(version_).c_str());
    websocket_->SetHeader("Device-Id", SystemInfo::GetMacAddress().c_str());
    websocket_->SetHeader("Client-Id", Board::GetInstance().GetUuid().c_str());

    // Step 3: Register callbacks
    websocket_->OnData([this](const char *data, size_t len, bool binary)
                       {
        // Forward to internal handler
        HandleIncomingData(data, len, binary); });

    websocket_->OnDisconnected([this]()
                               {
                                   ESP_LOGW(TAG, "WebSocket disconnected.");
                                   SetError(Lang::Strings::CONNECTION_LOST);
                                   // Optionally attempt reconnect logic here
                               });

    // Step 4: Connect to WebSocket server
    if (!websocket_->Connect(url.c_str()))
    {
        ESP_LOGE(TAG, "Failed to connect to WebSocket server, code=%d", websocket_->GetLastError());
        SetError(Lang::Strings::SERVER_NOT_CONNECTED);
        return false;
    }

    // Step 5: Construct and send 'hello' message
    cJSON *root = cJSON_CreateObject();
    cJSON_AddStringToObject(root, "type", "hello");
    cJSON_AddNumberToObject(root, "version", version_);

    char *json_str = cJSON_PrintUnformatted(root);
    std::string message(json_str);
    cJSON_free(json_str);
    cJSON_Delete(root);

    if (!websocket_->SendText(message))
    {
        ESP_LOGE(TAG, "Failed to send hello message.");
        SetError(Lang::Strings::SEND_FAILED);
        return false;
    }

    // Step 6: Wait for server acknowledgment (e.g., hello ack)
    EventBits_t bits = xEventGroupWaitBits(
        event_group_handle_,
        WEBSOCKET_PROTOCOL_SERVER_HELLO_EVENT,
        pdTRUE,              // Clear bits on exit
        pdFALSE,             // Wait for any bit
        pdMS_TO_TICKS(10000) // Timeout after 10 seconds
    );

    if (!(bits & WEBSOCKET_PROTOCOL_SERVER_HELLO_EVENT))
    {
        ESP_LOGE(TAG, "Timeout waiting for server hello response.");
        SetError(Lang::Strings::SERVER_RESPONSE_TIMEOUT);
        return false;
    }

    ESP_LOGI(TAG, "WebSocket started successfully.");
    return true;
}

