```cpp
std::vector<uint8_t> WrapAsBinaryProtocol2(const AudioStreamPacket& packet)
{
    size_t payload_size = packet.payload.size();
    size_t total_size = sizeof(BinaryProtocol2) + payload_size;

    std::vector<uint8_t> buffer(total_size);
    BinaryProtocol2* bp2 = reinterpret_cast<BinaryProtocol2*>(buffer.data());

    bp2->version = htons(2);
    bp2->type = htons(0); // Assuming OPUS
    bp2->reserved = 0;
    bp2->timestamp = htonl(packet.timestamp);
    bp2->payload_size = htonl(payload_size);

    memcpy(bp2->payload, packet.payload.data(), payload_size);

    return buffer;
}
