    // Check WebSocket validity and connectivity
    if (websocket_ == nullptr || !websocket_->IsConnected())
    {
        ESP_LOGE(TAG, "WebSocket is not connected");
        SetError(Lang::Strings::CONNECTION_ERROR);
        return false;
    }

    std::vector<uint8_t> wrapped_payload;

    if (version_ == 2)
    {
        // Wrap according to BinaryProtocol2 format
        size_t payload_size = packet->payload.size();
        size_t total_size = sizeof(BinaryProtocol2) + payload_size;

        wrapped_payload.resize(total_size);
        BinaryProtocol2 *bp2 = reinterpret_cast<BinaryProtocol2 *>(wrapped_payload.data());

        bp2->version = htons(2);
        bp2->type = htons(0); // OPUS assumed
        bp2->reserved = 0;
        bp2->timestamp = htonl(packet->timestamp);
        bp2->payload_size = htonl(static_cast<uint32_t>(payload_size));

        memcpy(bp2->payload, packet->payload.data(), payload_size);
    }
    else if (version_ == 3)
    {
        // Wrap according to BinaryProtocol3 format
        size_t payload_size = packet->payload.size();
        size_t total_size = sizeof(BinaryProtocol3) + payload_size;

        wrapped_payload.resize(total_size);
        BinaryProtocol3 *bp3 = reinterpret_cast<BinaryProtocol3 *>(wrapped_payload.data());

        bp3->type = 0; // OPUS assumed
        bp3->reserved = 0;
        bp3->payload_size = htons(static_cast<uint16_t>(payload_size));

        memcpy(bp3->payload, packet->payload.data(), payload_size);
    }
