bool WebsocketProtocol::OpenAudioChannel()
{
    // Step 1: Ensure WebSocket is connected
    if (websocket_ == nullptr || !websocket_->IsConnected())
    {
        ESP_LOGE(TAG, "WebSocket not connected");
        SetError(Lang::Strings::CONNECTION_ERROR);
        return false;
    }

    // Step 2: Generate the 'hello' message for opening the audio channel
    std::string hello_message = GetHelloMessage();

    // Step 3: Send the message via WebSocket
    if (!websocket_->Send(hello_message))
    {
        ESP_LOGE(TAG, "Failed to send hello message: %s", hello_message.c_str());
        SetError(Lang::Strings::SERVER_ERROR);
        return false;
    }

    // Step 4: Wait for server acknowledgment (up to 5 seconds)
    EventBits_t uxBits = xEventGroupWaitBits(
        event_group_handle_,
        WEBSOCKET_PROTOCOL_SERVER_HELLO_EVENT,
        pdTRUE,               // Clear bits on exit
        pdFALSE,              // Wait for any bit
        pdMS_TO_TICKS(5000)); // Timeout after 5 seconds

    if ((uxBits & WEBSOCKET_PROTOCOL_SERVER_HELLO_EVENT) == 0)
    {
        ESP_LOGE(TAG, "Timeout waiting for server hello acknowledgment");
        SetError(Lang::Strings::SERVER_TIMEOUT);
        return false;
    }

    // Success: Audio channel opened and acknowledged
    return true;
}

